const ElephantLogoSVG: React.FC<{ width: number }> = ({ width }) => (
  <SvgXml xml={elephantLogoXml} width={width} height={width * (237 / 182)} />
);

// ── Splash Screen ─────────────────────────────────────────────────────────────
interface Props {
  onFinish?: () => void;
}

const SplashScreen: React.FC<Props> = ({ onFinish }) => {
  const fadeAnim  = useRef(new Animated.Value(0)).current;
  const scaleAnim = useRef(new Animated.Value(0.88)).current;
  const exitAnim  = useRef(new Animated.Value(1)).current;

  // Scale logo to 60% screen width, max 280px (portrait logo)
  const logoWidth = Math.min(SW * 0.6, 280);

  useEffect(() => {
    Animated.sequence([
      // Pop in
      Animated.parallel([
        Animated.timing(fadeAnim, {
          toValue: 1,
          duration: 650,
          easing: Easing.out(Easing.cubic),
          useNativeDriver: true,
        }),
        Animated.spring(scaleAnim, {
          toValue: 1,
          friction: 7,
          tension: 50,
          useNativeDriver: true,
        }),
      ]),
      // Hold
      Animated.delay(1500),
      // Fade out
      Animated.timing(exitAnim, {
        toValue: 0,
        duration: 500,
        easing: Easing.in(Easing.ease),
        useNativeDriver: true,
      }),
    ]).start(() => {
      onFinish?.();
      // navigation.replace('Landing');
    });
  }, []);

  return (
    <Animated.View style={[styles.container, { opacity: exitAnim }]}>
      <StatusBar barStyle="light-content" backgroundColor="#101010" />
      <Animated.View
        style={{
          opacity: fadeAnim,
          transform: [{ scale: scaleAnim }],
        }}
      >
        <ElephantLogoSVG width={logoWidth} />
      </Animated.View>
    </Animated.View>
  );
};

export default SplashScreen;

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#101010',
    justifyContent: 'center',
    alignItems: 'center',
  },
});

/*
 * ── Setup ────────────────────────────────────────────────────
 *  npm install react-native-svg
 *  cd ios && pod install
 *
 *  Wire into AppNavigator as the first screen:
 *    <RootStack.Screen
 *      name="Splash"
 *      component={SplashScreen}
 *      options={{ headerShown: false, gestureEnabled: false }}
 *    />
 *    initialRouteName="Splash"
 *
 *  Then uncomment: navigation.replace('Landing');
 * ────────────────────────────────────────────────────────────
 */
